diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..f3e8a990a1df 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2229,10 +2229,16 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return BitOp;
     }

-    // Left or right might be masked.
-    if (SimplifyDemandedInstructionBits(*II))
-      return &CI;
-
+    // fshl(X, 0, Y) --> shl X, Y
+    // fshl(X, undef, Y) --> shl X, Y
+    // if Y is known to be in range [0, BitWidth).
+    if (IID == Intrinsic::fshl &&
+        (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))) {
+      Value *ShAmt = II->getArgOperand(2);
+      KnownBits Known = computeKnownBits(ShAmt, /*Depth=*/0, II);
+      if (Known.getMaxValue().ult(BitWidth))
+        return BinaryOperator::CreateShl(Op0, ShAmt);
+    }
     // The shift amount (operand 2) of a funnel shift is modulo the bitwidth,
     // so only the low bits of the shift amount are demanded if the bitwidth is
     // a power-of-2.

